cur = pg.cursor()
count = 0
for r in PRODUCTS:
    name = r.get("name","")
    cat  = r.get("category","")
    sub  = r.get("subcategory","")
    price = float(r.get("price") or 0)
    disc  = r.get("discount_price") or None
    disc  = float(disc) if disc else None
    stock = r.get("stock_status","In Stock") or "In Stock"
    desc  = r.get("description","") or ""
    img   = r.get("image","") or ""
    if img and not img.startswith("http"):
        img = "https://mahalaxmifashionhub.com/" + img
    best  = bool(int(r.get("best_seller",0) or 0))
    new   = int(r.get("newest",0) or 0)

    cur.execute("""
        INSERT INTO products
          (name,category,subcategory,price,discount_price,stock_status,
           description,image,best_seller,newest,created_at)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,NOW())
        ON CONFLICT DO NOTHING
    """, (name,cat,sub,price,disc,stock,desc,img,best,new))
    count += 1

pg.commit()
cur.close()
